var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"아앗, 전대원 분들! 그리로 가면 안 되죠!","JPN":"ああっ、戦隊員の皆さん！　そっちじゃないです！","ENG":"Ahh, everyone! Don’t go that way!","TWN":"欸欸，各位戰隊員！不是往那裡啦！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"A2! A2 좌표라고요!","JPN":"A2！　A2座標ですってば！","ENG":"A2! Coordinates A2!","TWN":"是A2！A2座標才對！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"그렇죠! 역시 우리 전대원 분들! 만세!","JPN":"それです！　さすがは皆さん！　やっほー！","ENG":"That’s it! Nice! As expected of our Division soldiers! Hooray!","TWN":"沒錯！不愧是我們的戰隊員！萬歲！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"새삼 느끼지만, 기술력이 굉장하네……. 거의 사람이잖아.","JPN":"今更だけど、すごい技術力だね……ほぼ人間じゃないの。","ENG":"Such an amazing technology… She's practically a real person.\\n\\n","TWN":"再次感受到科技的厲害……跟人根本沒什麼兩樣嘛！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런데 레버넌트 씨, 지금 뭐 하는 거예요?","JPN":"ところでレヴナントさん、今何やってるんですか？","ENG":"Wait, Revenant, what are you doing?","TWN":"不過亡靈小姐，請問你現在在做什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"잠깐만……. 거의 다 됐으니까…….","JPN":"ちょっと待って……もうすぐだから……","ENG":"Just a moment... Almost got it...","TWN":"等我一下……就快好了……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ALICIA_NPC_NULL_OLD","text":{"KOREA":"앗? 자, 잠깐만요! 그쪽 회로는 함부로 건드리시면……!","JPN":"えっ？　ま、待ってください！　そっちの回路を勝手にいじったら……！","ENG":"Ah? Wait! If you mess with that circuit...!","TWN":"嗯？喂，快住手！那邊的線路不能隨便亂碰……！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALICIA_NPC_NULL_OLD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"역시 인공지능의 수준은 높아도 함선 구조 자체는 제식이네.","JPN":"やっぱり人工知能のレベルは高くても、艦船の構造自体は他の機体と同じね。","ENG":"As expected, even if the A.I. tech is this advanced, the ship structure itself is pretty standard.","TWN":"就算有很高的人工智慧，但艦船本身的結構是固定的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"인공지능이 멎었잖아요?! 어서 원래대로 돌려 두세요!","JPN":"人工知能が止まってるじゃないですか！？　早く元どおりに戻してください！","ENG":"You disabled the A.I.?! Hey, turn it back on!","TWN":"人工智慧不說話咧？！你快點把它弄回去啦！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"안 돼. 애초에 내가 나갔다는 걸 보고할 수 없게 한 거니까.","JPN":"ダメ。元々私が出たことを報告できなくするためにやったんだから。","ENG":"No. I don’t want it to be able to report that I’ve left.","TWN":"不行，我就是要讓她不能打小報告，說我跑出去。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"무슨 말이에요? 나가다니 어디로?","JPN":"どういうことですか？　出るってどこに？","ENG":"What are you talking about? Where are you going?","TWN":"你在說什麼？你要去哪裡？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_SCAENA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"전술 현황판을 봐 봐. 이유는 모르겠지만 아까부터 알렉스 씨의 신호가 앞으로 나아가지 못하고 있어.","JPN":"戦術の現状を見てみて。理由はわからないけど、さっきからアレックスさんの信号が前に進めずにいるの。","ENG":"Look at the tactical status board. I don’t know why, but Alex’s signal hasn’t moved for a while.","TWN":"你看這個戰術儀表板，從剛剛開始，不知道為什麼，雅蕾克絲的訊號就無法再往前。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"더 늦었다간 중앙대로에 포격이 떨어질 거야.","JPN":"遅くなると中央通りに砲撃が落ちるよ。","ENG":"If we’re too late, the main street will be battered down.","TWN":"不快一點的話，砲彈會打到中央大道的！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래서 막으러 가겠다고요?","JPN":"だから止めに行くって言ってるんですか？","ENG":"So you’re going to go stop it?","TWN":"所以你要去擋砲彈？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……영웅 나셨네, 진짜. 자의식이 너무 비대한 거 아니에요?","JPN":"……ヒーローじゃないっつーの、まったく。自意識過剰じゃないですか？","ENG":"...You really have a savior complex, don’t you? Isn’t your sense of responsibility towards others a little too high?","TWN":"……有夠逞英雄的，你是不是太高估你自己啦？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"정부군이 저것들을 가만 놔두겠어요? 국가 기관을 너무 물로 보는 거 아니냐고요!","JPN":"政府軍があれを放っておくわけないでしょう？　国家機関はバカじゃないんです！","ENG":"You think the government forces will just let them get away with that? You think the government is a complete joke?","TWN":"你覺得政府軍會坐視不管嗎？未免也太小看國家機關！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하지만 내버려 두면 피해가 커져.","JPN":"でも放っておいたら被害が大きくなるよ。","ENG":"But if we do nothing, the damage will be even worse.","TWN":"但是再不出手的話，恐怕會造成更大的傷害！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그럼 경찰이랑 군대는 뭐하러 월급 준대요? 응원봉 흔들라고?","JPN":"じゃあ警察と軍隊はなんのためにお金貰ってると思ってるんですか？　応援団でもないでしょ？","ENG":"Then what the hell are they paying the police and the army to do? Wave a little stick around?","TWN":"你以為警察和軍隊是幹什麼吃的？每個月拿薪水不用辦事嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"반역자가 살림 걱정해 줄 정도로 썩어 빠진 나라면 차라리 그냥 망하라고 해요!","JPN":"反逆者に心配されるほど腐った国なら、いっそ滅びた方がマシでしょう！","ENG":"If a country has gotten so rotten to the level a traitor worries about it, just let it die!","TWN":"若是這個國家已經腐敗到，需要讓一個叛國賊來擔心存亡的問題，那不如就讓它毀滅吧！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저건 레버넌트 씨만 해결할 수 있는 문제도 아니에요. 그냥 이 나라에 늘상 있던 일이라고요.","JPN":"あれはレヴナントさんしか解決できない問題でもありません。この国の日常茶飯なんですよ。","ENG":"It’s not the kind of problem that only you can solve! It’s something that’s always going to happen in this country.","TWN":"這也不是光靠你就可以解決的問題，這是這個國家的常態！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"중사 말대로 나만 해결할 수 있는 문제는 아냐.","JPN":"軍曹の言うとおり、私でなくても解決できる問題だよ。","ENG":"As you said, I'm not the only one who can solve this problem.","TWN":"中士說的沒錯，這不是光靠我就可以解決的問題，"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그렇지만 이건, 내가 해결해야 할 문제야.","JPN":"でもこれは、私が解決しなければならない問題なの。","ENG":"But it is a problem I need to solve, regardless.","TWN":"卻是我必須解決的問題。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"다녀올게. 엄마를 잘 부탁해.","JPN":"行ってくる。お母さんをよろしくね。","ENG":"I’ll be right back. Take care of mom.","TWN":"我走了，我媽就拜託你了！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트 씨!! 레버넌트 씨!!","JPN":"レヴナントさん！！　レヴナントさん！！","ENG":"Revenant!! Revenant!!","TWN":"亡靈小姐！！亡靈小姐！！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"엄마, 나는 반역자야.","JPN":"お母さん、私は反逆者だよ。","ENG":"Mom, I’m a traitor.","TWN":"媽，我是叛國賊。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"국장님 말이 맞아. 내가 자크를 죽였어.","JPN":"局長が言ったとおり。私がジャックを殺したの。","ENG":"The Chief was right. I killed Jacques.","TWN":"部長說的沒錯，是我殺死札克的。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"엄마를 비참하게 만든 반군들을 전부 죽여 버리면, 엄마도 행복해질 수 있을 줄 알았으니까.","JPN":"お母さんを惨めにした反乱軍を全部殺せば、お母さんも幸せになると思ったから。","ENG":"After what they did to Mom, I thought that if all of those despicable rebels died, Mom would be happy again.","TWN":"叛軍把媽害得那麼慘，我以為只要殺光他們，媽就可以找回幸福。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"그놈들에게 몽땅 떠넘기면, 마음이 편했으니까.","JPN":"全部あいつらに押し付けると、心が楽になったから。","ENG":"When I put all the blame on them, I felt relief.","TWN":"因為只要把氣出在他們身上，我的心就可以得釋放。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"그런데 이제는 모르겠어.","JPN":"でも今はわからないの。","ENG":"But I’m not so sure anymore.","TWN":"但我現在也不太清楚，"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"그 날 방아쇠를 당길 때 내가 화를 냈는지.","JPN":"あの日引き金を引いた時、私は怒っていたのかな。","ENG":"Was I full of anger that day when I pulled the trigger?","TWN":"那天我扣下板機時，究竟是在生氣？"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"아니면 웃고 있었는지.","JPN":"それとも笑っていたのかな。","ENG":"Or was I laughing?","TWN":"還是在笑？"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"나는 아무것도 몰랐어.","JPN":"私は何も知らなかったの。","ENG":"I just don’t know anymore.","TWN":"我真的不知道。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"미안해. 엄마.\xA0","JPN":"ごめんね。お母さん。\xA0","ENG":"I’m sorry. Mom.\xA0","TWN":"媽，對不起。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"바보 같은 딸이라서.","JPN":"バカな娘で。","ENG":"For being such a foolish daughter.","TWN":"我是個傻女兒。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};